#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar(); // consume newline after T
    for(int t=0;t<T;++t){
        char buf[128];
        if(!fgets(buf,sizeof(buf),stdin)) break;
        size_t len=strlen(buf);
        if(len && buf[len-1]=='\n') buf[--len]='\0';
        int N; if(scanf("%d",&N)!=1) N=0; getchar(); // consume newline after N
        for(int i=0;i<N;++i) printf("%s",buf);
        printf("\n");
    }
    return 0;
}

